import subprocess

def convertDocument(input_file, output_file, output_format):
    # Check if the input file exists
    import os.path
    if not os.path.exists(input_file):
        raise FileNotFoundError("Input file does not exist")
    
    # Set the command for LibreOffice conversion
    command = [
        'libreoffice',
        '--headless',  # Run in headless mode
        '--convert-to', f'{output_format}:writer_pdf_Export',  # Convert to specified format
        input_file,
        '--outdir', os.path.dirname(output_file)  # Output directory
    ]
    
    # Execute the command
    try:
        subprocess.run(command, check=True)
    except subprocess.CalledProcessError as e:
        raise RuntimeError("Failed to convert document") from e

